#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int target = arr[K - 1];
        int pos = 0;
        for (int i = 0; i < N; i++) {
            if (arr[i] == target) {
                pos = i + 1;
                break;
            }
        }
        printf("%d\n", pos);
    }
    return 0;
}

