import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            Arrays.sort(arr);
            int target = arr[K - 1];
            int pos = 0;
            for (int i = 0; i < N; i++) {
                if (arr[i] == target) {
                    pos = i + 1;
                    break;
                }
            }
            System.out.println(pos);
        }
    }
}

